steps.script:
var dlg=null
for n in tree.root.get_children():
	if n is ConfirmationDialog and n.visible:
		dlg=n
return dlg != null

var dlg=null
for n in tree.root.get_children():
	if n is ConfirmationDialog and n.visible:
		dlg=n
if dlg==null:
	return false
dlg.get_ok_button().emit_signal("pressed")
return true

var km=GameState.get_unit("U_KOMMANDOS_H")
var bw=GameState.get_unit("U_BATTLEWAGON_G").models[0].position
var placed=0
for m in km.models:
	if m.get("alive",false) and m.position != null:
		var dx=float(m.position.x)-float(bw.x)
		var dy=float(m.position.y)-float(bw.y)
		if sqrt(dx*dx+dy*dy) < 400.0:
			placed+=1
return placed
